  PermissionValue,
} from '../models/invoicesCashbackPermission.model';

class InvoiceCashbackPermissionRepository {
  async getPermission(params: GetPermissionParams): Promise<PermissionValue | null> {
    const result = await invoiceCashbackPermissionApi.getPermission(params);
    return result?.data?.value ?? null;
  }

  async savePermission(document: PermissionDocumentInput): Promise<PermissionDocument> {
    return invoiceCashbackPermissionApi.savePermission(document);
  }
}

export const invoiceCashbackPermissionRepository = new InvoiceCashbackPermissionRepository();

